```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the written data
    std::vector<uint8_t> buffer;

    // Create a buffer_write_adaptor for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Track total bytes written
    std::size_t total_written = 0;

    // Write each chunk with size checking
    for (const auto& chunk : chunks) {
        // Check available free space before writing
        auto free_space = adaptor.free();

        // Calculate how much we can write from this chunk
        std::size_t bytes_to_write = std::min(free_space, chunk.size());

        // Write the portion that fits
        if (bytes_to_write > 0) {
            adaptor.write(chunk.data(), bytes_to_write);
            total_written += bytes_to_write;
        }

        // If we couldn't write the entire chunk, break or handle as needed
        if (bytes_to_write < chunk.size()) {
            break; // or throw exception based on requirements
        }
    }

    // Return the final buffer size
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a buffer_read_adaptor for the source buffer
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;
    std::size_t remaining = adaptor.size();

    // Read until buffer is empty
    while (remaining > 0) {
        // Calculate chunk size for this read
        std::size_t current_chunk_size = std::min(chunk_size, remaining);

        // Create destination buffer for this chunk
        std::vector<uint8_t> chunk(current_chunk_size);

        // Read the chunk
        adaptor.read(chunk.data(), current_chunk_size);

        // Append to result
        result.insert(result.end(), chunk.begin(), chunk.end());

        // Update remaining data
        remaining = adaptor.size();
    }

    return result;
}
